import { useState, useEffect, useCallback, useRef } from 'react';
import { api, apiPost } from '../utils/api';
import useUserBots from '../hooks/useUserBots';
import LoadingState from '../components/LoadingState';
import usePageTitle from '../hooks/usePageTitle';
import { tokens } from '../styles/tokens';
import s from './EmergencyControlsPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

function StatusDot({ active }) {
  const color = active ? C.green : C.red;
  return (
    <span className={s.statusDot}
      style={{ backgroundColor: color, boxShadow: `0 0 8px ${color}` }} />
  );
}

export default function EmergencyControlsPage() {
  usePageTitle('Emergency Controls');
  const { bots: userBots } = useUserBots();
  const BOTS = userBots.map(b => ({ name: b.name, clientId: b.client_id || b.clientId, accent: b.color || C.blue }));
  const [health, setHealth] = useState(null);
  const [sources, setSources] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [killActive, setKillActive] = useState(false);
  const [confirmStep, setConfirmStep] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [actionLoading, setActionLoading] = useState(false);
  const [botStates, setBotStates] = useState({});
  const [actionMsg, setActionMsg] = useState('');

  // Track user interactions to avoid poll overwriting user-modified state
  const userInteractingRef = useRef(false);
  const confirmStepRef = useRef(0);
  const cooldownRef = useRef(0);
  const actionLoadingRef = useRef(false);
  const hasLoadedOnceRef = useRef(false);

  // Keep refs in sync with state
  useEffect(() => { confirmStepRef.current = confirmStep; }, [confirmStep]);
  useEffect(() => { cooldownRef.current = cooldown; }, [cooldown]);
  useEffect(() => { actionLoadingRef.current = actionLoading; }, [actionLoading]);

  const fetchHealth = useCallback(async (isInitial = false) => {
    // Only show loading spinner on initial load, not on polls
    if (isInitial) {
      setLoading(true);
    }
    setError(null);
    try {
      const [data, srcData] = await Promise.all([
        api('/control/health'),
        api('/system/sources'),
      ]);
      if (data) {
        setHealth(data);
        // Only update kill switch from API if user is NOT mid-interaction
        // (not in confirm flow, not in cooldown, not performing an action)
        const isUserBusy = confirmStepRef.current > 0 || cooldownRef.current > 0 || actionLoadingRef.current;
        if (!isUserBusy) {
          setKillActive(data.killSwitch === true || data.kill_switch === true || data.killed === true);
        }
        const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
        const states = {};
        const bots = data.bots || [];
        if (Array.isArray(bots)) {
          bots.forEach(b => {
            const name = (b.name || '').toUpperCase();
            if (PAPER_BOTS.has(name.toLowerCase())) return;
            states[name] = b.status || b.state || 'unknown';
          });
        } else if (typeof bots === 'object' && bots !== null) {
          // Handle object format: { alpha: { status: 'OK', ... }, beta: { ... } }
          Object.entries(bots).forEach(([k, v]) => {
            if (PAPER_BOTS.has(k.toLowerCase())) return;
            if (typeof v === 'object' && v !== null) {
              states[k.toUpperCase()] = v.status || v.state || 'unknown';
            }
          });
        }
        setBotStates(states);
      }
      if (srcData) setSources(srcData);
      hasLoadedOnceRef.current = true;
    } catch (e) {
      setError(e.message || 'Failed to load data');
    } finally {
      if (isInitial) {
        setLoading(false);
      }
    }
  }, []);

  useEffect(() => {
    fetchHealth(true);
    const id = setInterval(() => fetchHealth(false), 5000);
    return () => clearInterval(id);
  }, [fetchHealth]);

  useEffect(() => {
    if (cooldown <= 0) return;
    const id = setInterval(() => setCooldown(prev => Math.max(0, prev - 1)), 1000);
    return () => clearInterval(id);
  }, [cooldown]);

  const handleKillSwitch = async () => {
    userInteractingRef.current = true;
    if (confirmStep < 2) {
      setConfirmStep(prev => prev + 1);
      return;
    }
    setActionLoading(true);
    setActionMsg('');
    const result = await apiPost('/control/kill', { action: 'activate' });
    setActionLoading(false);
    if (result) {
      setKillActive(true);
      setCooldown(30);
      setActionMsg('Kill switch activated - all trading halted');
    } else {
      setActionMsg('Failed to activate kill switch');
    }
    setConfirmStep(0);
    userInteractingRef.current = false;
    setTimeout(() => setActionMsg(''), 5000);
    fetchHealth(false);
  };

  const handleResetKill = async () => {
    if (cooldown > 0) return;
    userInteractingRef.current = true;
    setActionLoading(true);
    const result = await apiPost('/control/kill', { action: 'deactivate' });
    setActionLoading(false);
    if (result) {
      setKillActive(false);
      setActionMsg('Kill switch deactivated - trading resumed');
    }
    setConfirmStep(0);
    userInteractingRef.current = false;
    setTimeout(() => setActionMsg(''), 5000);
    fetchHealth(false);
  };

  const handleStopBot = async (botName) => {
    userInteractingRef.current = true;
    setActionLoading(true);
    const result = await apiPost('/control/kill', { action: 'stop_bot', bot: botName });
    setActionLoading(false);
    userInteractingRef.current = false;
    setActionMsg(result ? `${botName} stopped` : `Failed to stop ${botName}`);
    setTimeout(() => setActionMsg(''), 4000);
    fetchHealth(false);
  };

  const cancelConfirm = () => {
    setConfirmStep(0);
    userInteractingRef.current = false;
  };

  const systemStatus = health?.status || health?.systemStatus || (killActive ? 'killed' : 'healthy');
  const systemColor = killActive ? C.red : systemStatus === 'healthy' ? C.green : C.amber;

  const killButtonLabels = ['KILL SWITCH', 'CONFIRM KILL', 'FINAL CONFIRM - ACTIVATE'];
  const killButtonColors = [C.red, '#CC3333', '#FF0000'];

  return (
    <LoadingState loading={loading} error={error} empty={!health} type='cards' onRetry={() => fetchHealth(true)}>
      <div className={s.page}>
        <h1 className={s.pageTitle}>Emergency Controls</h1>
        <p className={s.pageSubtitle}>Kill switch and emergency stop controls</p>

        {/* Kill switch warning banner */}
        {killActive && (
          <div className={s.warningBanner}>
            <div className={s.pulseDot} />
            <div>
              <div className={s.warningTitle}>KILL SWITCH ACTIVE</div>
              <div className={s.warningBody}>All trading is halted. No new orders will be placed by any bot.</div>
            </div>
          </div>
        )}

        {/* Action feedback */}
        {actionMsg && (
          <div className={actionMsg.includes('Failed') ? s.actionError : s.actionSuccess}>
            {actionMsg}
          </div>
        )}

        {/* Status indicators */}
        <div className={s.statusRow}>
          <div className={s.statusCard}>
            <div className={s.statusLabel}>System Health</div>
            <div className={s.statusValue}>
              <StatusDot active={!killActive && systemStatus === 'healthy'} />
              <span className={s.statusText} style={{ color: systemColor }}>{systemStatus}</span>
            </div>
          </div>
          <div className={s.statusCard} style={{ borderColor: killActive ? C.red : undefined }}>
            <div className={s.statusLabel}>Kill Switch</div>
            <div className={s.statusValue}>
              <span className={s.statusText} style={{ color: killActive ? C.red : C.green }}>
                {killActive ? 'ENGAGED' : 'DISENGAGED'}
              </span>
            </div>
          </div>
          <div className={s.statusCard}>
            <div className={s.statusLabel}>Active Bots</div>
            <div className={s.statusText} style={{ color: C.blue }}>
              {Object.values(botStates).filter(st => st === 'active' || st === 'online' || st === 'running').length} / {BOTS.length}
            </div>
          </div>
        </div>

        {/* Kill switch section */}
        <div className={s.killPanel} style={{ border: `2px solid ${killActive ? C.red : C.border}` }}>
          <div className={s.killTitle}>Master Kill Switch</div>
          <div className={s.killDesc}>
            {killActive
              ? 'Kill switch is currently active. All trading is halted. Reset to resume operations.'
              : 'Activating the kill switch will immediately halt all trading across all bots. This requires double confirmation.'}
          </div>

          {!killActive ? (
            <div>
              <button
                onClick={handleKillSwitch}
                disabled={actionLoading}
                className={s.killBtn}
                style={{
                  backgroundColor: killButtonColors[confirmStep],
                  padding: confirmStep === 2 ? '16px 48px' : '14px 40px',
                  fontSize: confirmStep === 2 ? 16 : 14,
                  boxShadow: confirmStep > 0 ? `0 0 20px ${killButtonColors[confirmStep]}66` : 'none',
                }}
              >
                {actionLoading ? 'ACTIVATING...' : killButtonLabels[confirmStep]}
              </button>
              {confirmStep > 0 && (
                <div className={s.confirmWrap}>
                  <button onClick={cancelConfirm} className={s.cancelBtn}>Cancel</button>
                  <div className={s.confirmHint}>
                    Step {confirmStep + 1} of 3 — {confirmStep === 1 ? 'Click once more to activate' : 'This is your last chance to cancel'}
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div>
              <button
                onClick={handleResetKill}
                disabled={cooldown > 0 || actionLoading}
                className={s.resetBtn}
                style={{
                  backgroundColor: cooldown > 0 ? C.surface2 : C.green,
                  color: cooldown > 0 ? C.textSecondary : C.bg,
                  cursor: cooldown > 0 || actionLoading ? 'not-allowed' : 'pointer',
                }}
              >
                {cooldown > 0 ? `COOLDOWN ${cooldown}s` : 'RESET KILL SWITCH'}
              </button>
              {cooldown > 0 && (
                <div className={s.cooldownWrap}>
                  <div className={s.cooldownTrack}>
                    <div className={s.cooldownFill} style={{ width: `${(cooldown / 30) * 100}%` }} />
                  </div>
                  <div className={s.cooldownHint}>Safety cooldown — please wait before resetting</div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Per-bot controls */}
        <div className={s.botSection}>
          <div className={s.sectionHeader}>Individual Bot Controls</div>
          <div className={s.botGrid}>
            {BOTS.map(bot => {
              const state = botStates[bot.name] || 'unknown';
              const isActive = state === 'active' || state === 'online' || state === 'running';
              return (
                <div key={bot.name} className={s.botCard} style={{ borderTop: `3px solid ${bot.accent}` }}>
                  <div className={s.botCardHeader}>
                    <span className={s.botName} style={{ color: bot.accent }}>{bot.name}</span>
                    <span className={s.botStatusBadge} style={{
                      backgroundColor: isActive ? `${C.green}22` : `${C.red}22`,
                      color: isActive ? C.green : C.red,
                    }}>
                      {state}
                    </span>
                  </div>
                  <div className={s.botClientId}>Client ID: {bot.clientId}</div>
                  <button
                    onClick={() => handleStopBot(bot.name)}
                    disabled={!isActive || killActive || actionLoading}
                    className={isActive && !killActive ? s.stopBtnActive : s.stopBtnDisabled}
                    style={{
                      backgroundColor: isActive && !killActive ? `${C.red}20` : C.surface,
                      color: isActive && !killActive ? C.red : C.textSecondary,
                      border: `1px solid ${isActive && !killActive ? C.red + '40' : C.border}`,
                    }}
                  >
                    {killActive ? 'KILLED' : isActive ? 'STOP BOT' : 'STOPPED'}
                  </button>
                </div>
              );
            })}
          </div>
        </div>

        {/* System health detail */}
        <div className={s.systemSection}>
          <div className={s.sectionHeader}>System State</div>
          {loading ? (
            <div className={s.systemLoading}>Loading health data...</div>
          ) : (
            <div>
              {(() => {
                const krakenSrc = sources?.sources?.find(src => src.name === 'Kraken');
                const krakenProSrc = sources?.sources?.find(src => src.name === 'KrakenPro');
                const krakenOnline = krakenSrc?.online;
                const krakenProOnline = krakenProSrc?.online;
                const krakenVal = krakenOnline ? `online ${krakenSrc?.detail || ''}`.trim() : 'disconnected';
                const krakenTrading = krakenProOnline ? 'connected' : botStates['NOVA'] === 'OK' ? 'via Nova Agent' : 'disconnected';
                return [
                  { label: 'API Server', value: health?.api || 'connected', good: true },
                  { label: 'IBKR Gateway', value: health?.ibkr || health?.gateway || 'port 4001', good: true },
                  { label: 'Kraken Data', value: krakenVal, good: !!krakenOnline },
                  { label: 'Kraken Trading', value: krakenTrading, good: !!krakenProOnline || botStates['NOVA'] === 'OK' },
                  { label: 'Kill Switch State', value: killActive ? 'ACTIVE' : 'INACTIVE', good: !killActive },
                  { label: 'Last Health Check', value: new Date().toLocaleTimeString(), good: true },
                  { label: 'Trading Enabled', value: killActive ? 'NO' : 'YES', good: !killActive },
                ];
              })().map((row, i) => (
                <div key={i} className={s.stateRow}>
                  <span className={s.stateLabel}>{row.label}</span>
                  <span className={s.stateValue} style={{ color: row.good ? C.green : C.red }}>
                    {row.value}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </LoadingState>
  );
}
